rawHtml.value:
{{`
<div style="
  display:flex;
  justify-content:center;
  align-items:center;
  width:100%;
">

  <div style="
    display:inline-flex;
    align-items:center;
    gap:8px;
    padding:6px 12px;
    border-radius:999px;
    background:#f3f4f6;
    font-family: Inter, system-ui, sans-serif;
    font-size:13px;
    color:#111827;
    border:1px solid #e5e7eb;
  ">

    <div style="
      width:26px;
      height:26px;
      border-radius:50%;
      background:#e5e7eb;
      display:flex;
      align-items:center;
      justify-content:center;
      font-weight:600;
      font-size:12px;
    ">
      ${
        globals.currentUser?.firstName
          ? globals.currentUser.firstName.charAt(0).toUpperCase()
          : "U"
      }
    </div>

    <div style="display:flex; flex-direction:column; line-height:1.1;">

      <span style="font-weight:600;">
        ${
          globals.currentUser?.firstName || globals.currentUser?.lastName
            ? `${globals.currentUser.firstName || ""} ${globals.currentUser.lastName || ""}`.trim()
            : "User"
        }
      </span>

      <span style="font-size:11px; color:#6b7280;">
        ${globals.currentUser?.title || "User"}
      </span>

    </div>

  </div>

</div>
`}}

