  .tooljet-ai-card-root {
    --bg: #f6f4ef;
    --ink: #12131a;
    --ink-soft: #4a4d5e;
    --ink-muted: #8b8e9f;
    --accent: #b04a2e;
    --navy: #1a2340;
    font-family: "Manrope", system-ui, sans-serif;
    background: var(--bg);
    color: var(--ink);
    padding: 24px;
  }
  .tooljet-ai-card-root * { box-sizing: border-box; margin: 0; padding: 0; }
  .tooljet-ai-card-root .panel-group {
    max-width: 640px;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .tooljet-ai-card-root .panel-label {
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--ink-muted);
    font-weight: 700;
    padding-left: 2px;
  }
  .tooljet-ai-card-root .ai-panel {
    background: linear-gradient(135deg, var(--navy) 0%, #2a3558 100%);
    color: #fff;
    border-radius: 10px;
    padding: 20px;
    position: relative;
    overflow: hidden;
    border: 1px solid rgba(255,255,255,0.05);
    box-shadow: 0 12px 28px rgba(26, 35, 64, 0.12);
  }
  .tooljet-ai-card-root .ai-panel::before {
    content: "";
    position: absolute;
    top: -40px;
    right: -40px;
    width: 180px;
    height: 180px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(176, 74, 46, 0.3) 0%, transparent 70%);
  }
  .tooljet-ai-card-root .ai-head {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 14px;
    position: relative;
    z-index: 1;
  }
  .tooljet-ai-card-root .ai-icon {
    width: 28px;
    height: 28px;
    border-radius: 7px;
    background: var(--accent);
    display: grid;
    place-items: center;
    font-size: 13px;
  }
  .tooljet-ai-card-root .ai-title {
    font-family: "Bricolage Grotesque", serif;
    font-size: 17px;
    font-weight: 600;
  }
  .tooljet-ai-card-root .ai-status {
    font-size: 10px;
    color: rgba(255,255,255,0.55);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin-top: 2px;
  }
  .tooljet-ai-card-root .ai-insights {
    display: flex;
    flex-direction: column;
    gap: 10px;
    position: relative;
    z-index: 1;
  }
  .tooljet-ai-card-root .ai-insight {
    display: flex;
    gap: 10px;
    padding: 12px 14px;
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 8px;
    font-size: 13px;
    line-height: 1.55;
  }
  .tooljet-ai-card-root .ai-insight-bullet {
    flex-shrink: 0;
    width: 20px;
    height: 20px;
    border-radius: 5px;
    background: rgba(176, 74, 46, 0.25);
    color: #ffb49c;
    display: grid;
    place-items: center;
    font-size: 11px;
    font-weight: 700;
    margin-top: 1px;
  }
  .tooljet-ai-card-root .ai-insight-bullet.flag {
    background: rgba(239, 159, 47, 0.25);
    color: #ffcf8a;
  }
  .tooljet-ai-card-root .ai-copy {
    flex: 1;
